import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"부록 | Clawdbot 튜토리얼","description":"Clawdbot 부록 장: 완전한 설정 참조, Gateway WebSocket API 프로토콜, 배포 옵션 및 개발 가이드.","frontmatter":{"title":"부록 | Clawdbot 튜토리얼","sidebarTitle":"설정, 배포, 개발 실전","subtitle":"부록","description":"Clawdbot 부록 장: 완전한 설정 참조, Gateway WebSocket API 프로토콜, 배포 옵션 및 개발 가이드.","tags":[],"order":340},"headers":[],"relativePath":"ko/moltbot/moltbot/appendix/index.md","filePath":"ko/moltbot/moltbot/appendix/index.md"}'),r={name:"ko/moltbot/moltbot/appendix/index.md"};function i(n,a,s,c,d,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="부록" tabindex="-1">부록 <a class="header-anchor" href="#부록" aria-label="Permalink to &quot;부록&quot;">​</a></h1><p>이 장은 Clawdbot의 고급 참조 문서와 개발 리소스를 제공하며, 완전한 설정 참조, Gateway WebSocket API 프로토콜 사양, 배포 옵션 및 개발 가이드를 포함합니다.</p><div class="info custom-block"><p class="custom-block-title">적용 시나리오</p><p>이 장은 Clawdbot의 내부 메커니즘을 깊이 이해하고, 고급 설정을 수행하고, 배포하거나 개발에 참여해야 하는 사용자에게 적합합니다. 처음 시작하는 경우 먼저 <a href="./../../start/getting-started/">빠른 시작</a> 장을 완료하는 것이 좋습니다.</p></div><h2 id="하위-페이지-탐색" tabindex="-1">하위 페이지 탐색 <a class="header-anchor" href="#하위-페이지-탐색" aria-label="Permalink to &quot;하위 페이지 탐색&quot;">​</a></h2><h3 id="완전한-설정-참조" tabindex="-1"><a href="./config-reference/">완전한 설정 참조</a> <a class="header-anchor" href="#완전한-설정-참조" aria-label="Permalink to &quot;[완전한 설정 참조](./config-reference/)&quot;">​</a></h3><p><strong>상세 설정 파일 참조</strong> - 모든 설정 항목, 기본값 및 예제를 다룹니다. Gateway, Agent, 채널, 도구 등 모듈의 완전한 설정 설명을 찾아보세요.</p><h3 id="gateway-websocket-api-프로토콜" tabindex="-1"><a href="./api-protocol/">Gateway WebSocket API 프로토콜</a> <a class="header-anchor" href="#gateway-websocket-api-프로토콜" aria-label="Permalink to &quot;[Gateway WebSocket API 프로토콜](./api-protocol/)&quot;">​</a></h3><p><strong>프로토콜 사양 문서</strong> - Gateway WebSocket 프로토콜의 완전한 사양을 포함하며, 엔드포인트 정의, 메시지 형식, 인증 방법 및 이벤트 구독 메커니즘을 다룹니다. 사용자 지정 클라이언트를 만들거나 Gateway를 통합해야 하는 개발자에게 적합합니다.</p><h3 id="배포-옵션" tabindex="-1"><a href="./deployment/">배포 옵션</a> <a class="header-anchor" href="#배포-옵션" aria-label="Permalink to &quot;[배포 옵션](./deployment/)&quot;">​</a></h3><p><strong>배포 방법 가이드</strong> - 다양한 플랫폼의 배포 방법: 로컬 설치, Docker, VPS, Fly.io, Nix 등. 다양한 환경에서 Clawdbot을 실행하는 방법을 알아보세요.</p><h3 id="개발-가이드" tabindex="-1"><a href="./development/">개발 가이드</a> <a class="header-anchor" href="#개발-가이드" aria-label="Permalink to &quot;[개발 가이드](./development/)&quot;">​</a></h3><p><strong>개발자 문서</strong> - 소스에서 빌드, 플러그인 개발, 테스트 및 기여 프로세스. Clawdbot 프로젝트 개발에 참여하거나 사용자 지정 플러그인을 작성하는 방법을 배우세요.</p><h2 id="학습-경로-권장" tabindex="-1">학습 경로 권장 <a class="header-anchor" href="#학습-경로-권장" aria-label="Permalink to &quot;학습 경로 권장&quot;">​</a></h2><p>요구 사항에 따라 적합한 학습 경로를 선택하세요:</p><h3 id="설정-및-운영-담당자" tabindex="-1">설정 및 운영 담당자 <a class="header-anchor" href="#설정-및-운영-담당자" aria-label="Permalink to &quot;설정 및 운영 담당자&quot;">​</a></h3><ol><li>먼저 <a href="./config-reference/">완전한 설정 참조</a>를 읽어 모든 설정 가능한 항목을 파악하세요.</li><li><a href="./deployment/">배포 옵션</a>을 참조하여 적합한 배포 방안을 선택하세요.</li><li>필요에 따라 Gateway WebSocket API 문서를 참조하여 통합하세요.</li></ol><h3 id="애플리케이션-개발자" tabindex="-1">애플리케이션 개발자 <a class="header-anchor" href="#애플리케이션-개발자" aria-label="Permalink to &quot;애플리케이션 개발자&quot;">​</a></h3><ol><li><a href="./api-protocol/">Gateway WebSocket API 프로토콜</a>을 읽어 프로토콜 메커니즘을 이해하세요.</li><li><a href="./config-reference/">완전한 설정 참조</a>를 확인하여 관련 기능을 구성하는 방법을 파악하세요.</li><li>프로토콜 예제를 참조하여 클라이언트를 구축하세요.</li></ol><h3 id="플러그인-기능-개발자" tabindex="-1">플러그인/기능 개발자 <a class="header-anchor" href="#플러그인-기능-개발자" aria-label="Permalink to &quot;플러그인/기능 개발자&quot;">​</a></h3><ol><li><a href="./development/">개발 가이드</a>를 읽어 개발 환경 및 빌드 프로세스를 파악하세요.</li><li><a href="./api-protocol/">Gateway WebSocket API 프로토콜</a>을 깊이 있게 이해하여 Gateway 아키텍처를 파악하세요.</li><li><a href="./config-reference/">완전한 설정 참조</a>를 참조하여 설정 시스템을 파악하세요.</li></ol><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">전제 지식</p><p>이 장을 깊이 있게 이해하기 전에 다음 내용을 완료했는지 확인하세요:</p><ul><li>✅ <a href="./../../start/getting-started/">빠른 시작</a>을 완료했습니다.</li><li>✅ 하나 이상의 채널을 구성했습니다(예: <a href="./../../platforms/whatsapp/">WhatsApp</a> 또는 <a href="./../../platforms/telegram/">Telegram</a>)</li><li>✅ 기본 AI 모델 구성에 대해 이해했습니다( <a href="./../../advanced/models-auth/">AI 모델 및 인증</a> 참조)</li><li>✅ JSON 설정 파일 및 TypeScript에 대한 기본적인 이해가 있습니다.</li></ul></div><h2 id="다음-단계-안내" tabindex="-1">다음 단계 안내 <a class="header-anchor" href="#다음-단계-안내" aria-label="Permalink to &quot;다음 단계 안내&quot;">​</a></h2><p>이 장의 학습을 완료한 후 다음을 수행할 수 있습니다:</p><ul><li><strong>고급 설정 수행</strong> - <a href="./config-reference/">완전한 설정 참조</a>를 참조하여 Clawdbot을 사용자 지정하세요.</li><li><strong>프로덕션 환경 배포</strong> - 적합한 배포 방안을 선택하려면 <a href="./deployment/">배포 옵션</a>을 따르세요.</li><li><strong>사용자 지정 기능 개발</strong> - 플러그인을 작성하거나 코드를 기여하려면 <a href="./development/">개발 가이드</a>를 참조하세요.</li><li><strong>기타 기능 심화 학습</strong> - <a href="./../../advanced/">고급 기능</a> 장을 탐색하세요. 예: 세션 관리, 도구 시스템 등</li></ul><div class="tip custom-block"><p class="custom-block-title">도움 찾기</p><p>사용 중 문제가 발생하면 <a href="./../../faq/troubleshooting/">문제 해결</a>에서 일반적인 문제의 해결책을 찾아보세요.</p></div>',26)])])}const f=e(r,[["render",i]]);export{b as __pageData,f as default};
